// Verify Svix-format webhook signature sent by Allo.
// Headers: webhook-id, webhook-timestamp, webhook-signature ("v1,<base64sig>[ v1,<base64sig>...]")
// Signed content = `${id}.${timestamp}.${rawBody}` (utf8)
// Secret format: whsec_<base64>. Decode base64 to get raw bytes, used as HMAC key.
const crypto = require('crypto');

const secret = $env.ALLO_WEBHOOK_SECRET;
if (!secret) throw new Error('ALLO_WEBHOOK_SECRET env var is not set on the n8n container');

const item = $input.first();
const headers = item.json.headers || {};
const id = headers['webhook-id'];
const timestamp = headers['webhook-timestamp'];
const sigHeader = (headers['webhook-signature'] || '').trim();
if (!id || !timestamp || !sigHeader) throw new Error('Missing Svix webhook headers (webhook-id / webhook-timestamp / webhook-signature)');

// Reject if timestamp is more than 5 min off (replay protection).
const now = Math.floor(Date.now() / 1000);
const tsNum = parseInt(timestamp, 10);
if (!Number.isFinite(tsNum) || Math.abs(now - tsNum) > 300) throw new Error('Webhook timestamp out of tolerance');

// Raw body is on item.binary.body when Webhook node has rawBody=true.
let rawBuf;
if (item.binary && item.binary.body && item.binary.body.data) {
  rawBuf = Buffer.from(item.binary.body.data, 'base64');
} else if (typeof item.json.body === 'string') {
  rawBuf = Buffer.from(item.json.body, 'utf8');
} else {
  rawBuf = Buffer.from(JSON.stringify(item.json.body || {}), 'utf8');
}

const signedContent = `${id}.${timestamp}.${rawBuf.toString('utf8')}`;
const secretBytes = Buffer.from(secret.replace(/^whsec_/, ''), 'base64');
const expected = crypto.createHmac('sha256', secretBytes).update(signedContent).digest('base64');

// Svix may send several space-separated v1,xxx values. Accept if any matches.
const signatures = sigHeader.split(' ').map(s => s.trim()).filter(Boolean);
let valid = false;
for (const sig of signatures) {
  const m = sig.match(/^v1,(.+)$/);
  if (!m) continue;
  const sigBuf = Buffer.from(m[1], 'base64');
  const expBuf = Buffer.from(expected, 'base64');
  if (sigBuf.length === expBuf.length && crypto.timingSafeEqual(sigBuf, expBuf)) { valid = true; break; }
}
if (!valid) throw new Error('Invalid Svix signature');

let parsed;
try { parsed = JSON.parse(rawBuf.toString('utf8')); } catch (e) { throw new Error('Body is not valid JSON: ' + e.message); }

// Bridge: expose `event` so the downstream Switch keeps matching.
return [{ json: { event: parsed.topic, payload: parsed } }];
